__kernel void hotspot(int iter,
                      __global const float *power,
                      __global const float *temp,
                      __global float *result,
                      int col,
                      int row,
                      int borderCols,
                      int borderRows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;
    const float amb_temp = 80.0f;

    int c = get_global_id(0);
    int r = get_global_id(1);

    if (r >= row || c >= col) return;

    int idx = r * col + c;

    for (int i = 0; i < iter; i++) {
        float delta;

        if (r == 0 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + 1] - temp[idx]) * Rx_1 +
                (temp[idx + col] - temp[idx]) * Ry_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }
        else if (r == 0 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp[idx - 1] - temp[idx]) * Rx_1 +
                (temp[idx + col] - temp[idx]) * Ry_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }
        else if (r == row - 1 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp[idx - 1] - temp[idx]) * Rx_1 +
                (temp[idx - col] - temp[idx]) * Ry_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }
        else if (r == row - 1 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + 1] - temp[idx]) * Rx_1 +
                (temp[idx - col] - temp[idx]) * Ry_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }
        else if (r == 0) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                (temp[idx + col] - temp[idx]) * Ry_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }
        else if (c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                (temp[idx - 1] - temp[idx]) * Rx_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }
        else if (r == row - 1) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                (temp[idx - col] - temp[idx]) * Ry_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }
        else if (c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                (temp[idx + 1] - temp[idx]) * Rx_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }
        else {
            delta = Cap_1 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                (amb_temp - temp[idx]) * Rz_1);
        }

        result[idx] = temp[idx] + delta;

        if (i < iter - 1) {
            temp[idx] = result[idx];
        }
    }
}
